var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"시간이 없어! 어떻게든 하지 않으면......!","JPN":"時間がない！　どうにかしないと……！","ENG":"We're running out of time! We must do something, or...","TWN":"沒時間了！再不想辦法的話……！"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면...... 비숍을 먼저 처리하세요.","JPN":"でしたら……ビショップを先に片づけてください。","ENG":"Then... you should take care of Bishop first.","TWN":"那就……先處理主教吧。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 어떻게든 틈을 만들어 볼게요.","JPN":"僕がどうにか隙を作ってみますから。","ENG":"I'll try to create an opening.","TWN":"我會想辦法幫妳製造機會。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무, 무슨 소리야? 우리의 적은 리플레이서 킹이라고. 그런데 비숍은 왜......?","JPN":"ど、どういうこと？　私たちの敵はリプレイサー・キングでしょ？　ビショップはどうして……？","ENG":"W-what are you talking about? Replacer King is the our archenemy here. Why Bishop, all of a sudden?","TWN":"你、你在說什麼？我們的敵人是克隆．帝皇啊。為什麼要處理主教……？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 스승님이 미나 양에게 테라사이드 시스템의 중추를 파괴하라고 했죠?","JPN":"ミナさん、師匠にテラサイドシステムの中枢を破壊するように言われたんですよね？","ENG":"Mina, Master told you to destroy the backbone of System Terraside, didn't she?","TWN":"米娜小姐，師父要妳破壞特拉賽德系統的中樞吧？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"맞아, 하지만 그건 불멸체 코어를 이야기하는 거잖아?","JPN":"うん、でもそれは不滅体コアのことでしょ？","ENG":"She did, but wasn't it the Immortal System Core that she was talking about?","TWN":"是啊，但那不是在說不滅者核心嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 퀸이나 다른 간부들을 재생시키는......","JPN":"リプレイサー・クイーンや他の幹部を再生するための……","ENG":"That's the one regenerating the Queen and other officers...","TWN":"讓克隆·女皇和其他幹部再生的……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그렇지 않아요.","JPN":"いいえ。","ENG":"You're mistaken.","TWN":"不是的。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"물론 불멸체 코어도 테라사이드 시스템의 주요 하부 시스템이긴 하지만, 그게 중추라고는 할 수 없죠.","JPN":"もちろん、不滅体コアもテラサイドシステムの主なシステムの一つですが、それが中枢とは言えません。","ENG":"Of course, the Immortal System Core is also an important part of System Terraside, but it's hardly the backbone.","TWN":"當然，不滅者核心是特拉賽德系統的主要子系統，但它不是中樞。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 그저 파괴와 재생을 통해 데이터를 수집하는 역할을 할 뿐,","JPN":"それは単に破壊と再生を通じて、データ収集の役割をするだけで、","ENG":"What it's doing is collect data gained from the process of destruction and regeneration.","TWN":"那只是透過破壞和再生，負責收集資料的東西。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"클리포트 레플리카 인자를 조합하는 궁극적인 기능은 컨트롤 브레인인 리플레이서 비숍이 담당하고 있어요.","JPN":"レプリカ・クリフォト・ファクターを組み合わせる究極の機能は、\\nコントロールブレーンであるリプレイサー・ビショップが担当しています。","ENG":"The master brain, Bishop, is the ultimate overseer of the Qliphoth Replica Factor production.","TWN":"組合逆卡巴拉複製因子的究極功能，是由作為控制大腦的克隆．主教負責。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그녀가 바로 테라사이드 시스템의 중추입니다.","JPN":"彼女がまさにテラサイドシステムの中枢なんです。","ENG":"In short, Bishop is the backbone of System Terraside.","TWN":"她就是特拉賽德系統的中樞。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇다고 해도...... 차라리 불멸체 코어를 먼저 파괴하면 굳이 비숍과 싸울 필요는 없잖아?","JPN":"そ、そうだとしても……いっそのこと不滅体コアを先に破壊しちゃえば、\\nビショップと戦う必要はないよね？","ENG":"B-but why do we have to fight her when we can just destroy the Immortal System Core?","TWN":"就、就算是那樣……我們先破壞了不滅者核心，不就不用和克隆．大主教戰鬥了嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배의 말대로 데이터 수집이 멈추면 클리포트 레플리카 인자도 만들 수 없을 테니까.","JPN":"先輩の言うとおり、データ収集が止まれば、\\nレプリカ・クリフォト・ファクターを作ることもできないだろうから。","ENG":"Like you said, they won't be able to produce any more Qliphoth Replica Factors if they can't collect any more data.","TWN":"按照前輩所說的，只要停止數據收集的話，他們就無法製造逆卡巴拉複製因子了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"아니요. 실질적으로 필요한 데이터는 이미 수집이 끝났을 겁니다.","JPN":"いいえ、実際に必要なデータは、すでに収集完了しているのだと思います。","ENG":"I don't think so. They should have finished collecting all the data they need by now.","TWN":"不是的。實際上，需要的資料已經收集完了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이제 와서 불멸체 코어를 파괴한다고 해도 그녀가 무사한 이상 클리포트 인자의 재배포를 막을 수는 없습니다.","JPN":"ここで不滅体コアを破壊するとしても、彼女が無事である限り、\\nクリフォト・ファクターの再配布を防ぐことはできません。","ENG":"Even if we were to destroy the Immortal System Core, we won't be able to stop them from redistributing the Qliphoth Factor as long as Bishop's alive.","TWN":"到了這個地步，就算破壞了不滅者核心，只要她平安無損，我們就無法阻止逆卡巴拉因子的再發送。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"무엇보다...... 불멸체 코어가 어디에 있다고 생각하시죠, 미나 양?","JPN":"何より……不滅体コアはどこにあると思いますか、ミナさん？","ENG":"Most of all... Where do you think the Immortal System Core is, Mina?","TWN":"更重要的是……米娜小姐，妳有想過不滅者核心在哪裡嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어? 그러고 보니 이곳엔 딱히 특별한 설비가 안 보이는데......","JPN":"え？　そういえば、ここにはそれっぽい設備が見当たらないけど……","ENG":"Huh? Come to think of it, I don't see any proper apparatus or equipment here.","TWN":"咦？這麼一說，這裡好像沒看到什麼特別的設備……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 다른 곳에 있는 거야?","JPN":"まさか他所にあるの？","ENG":"Is it somewhere else?","TWN":"難道在其他地方嗎？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이제와서 불멸체 코어 같은 중요한 물건을 다른 곳에 두지는 않았을 겁니다.","JPN":"ここにきて、不滅体コアのような重要なものを他所に置くことはしないと思います。","ENG":"I doubt they'd move something as important as the Immortal System Core to some place else.","TWN":"事到如今，他們不會把不滅者核心這麼重要的東西放在別的地方。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그건 분명 여기에 있어요.","JPN":"それは、間違いなくここにあります。","ENG":"It's definitely here.","TWN":"肯定就在這裡。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼?","JPN":"じゃあ……","ENG":"What are you saying?","TWN":"所以？"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 킹과 몇 번 부딪쳐 보고 확신이 섰습니다.","JPN":"リプレイサー・キングと何度か打ち合ってみて確信が持てました。","ENG":"Those few blows I took from the Replacer King were enough to make me realize.","TWN":"和克隆．帝皇交手了幾次後，我可以肯定。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 킹은 분명 강하지만, 평범한 인간이에요.","JPN":"彼は確かに強いですが、普通の人間です。","ENG":"He's definitely strong, but he's just an ordinary human.","TWN":"儘管克隆．帝皇很強，但他只是普通的人類。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 저 자는 저와 부딪칠 때마다 클리포트 인자의 힘을 방출하고 있었어요.","JPN":"ですが、彼は僕と打ち合う度に、クリフォトの力を放出していました。","ENG":"But his every blow was filled with the energy of Qliphoth Factors.","TWN":"然而每次和我交手的時候，他都會放出逆卡巴拉因子的力量。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 그렇다는 건......","JPN":"え？　それは、つまり……","ENG":"Huh? Then it means...","TWN":"什麼？這麼說的話……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저 남자가 자기자신을 제 5종 침식체로 진화시킨 게 아닌 이상 가능성은 하나뿐입니다.","JPN":"彼が自ら第5種侵食体になっていない限り、可能性は１つだけです。","ENG":"If he didn't evolve himself into a Category 5 C.O., there's only one possibility.","TWN":"那個男人沒有把自己進化成第5級侵蝕體的話，那就只有一種可能了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저 남자는 스스로의 몸에 불멸체 코어를 박아 넣고 융합한 겁니다.","JPN":"彼は、自分の体に不滅体コアを埋め込んで、融合しているんです。","ENG":"He planted the Immortal System Core inside his body and fused himself with it.","TWN":"他把不滅者核心放進自己的身體裡融合了。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 불멸체 코어를 통해 미나 양에게서 추출한 클리포트 인자의 힘을 사용하는 거죠.","JPN":"その不滅体コアを通じて、ミナさんから抽出したクリフォト・ファクターの力を繰り出しているのです。","ENG":"It's through the Immortal System Core that he's able to use the power of the Qliphoth Factors extracted from you.","TWN":"所以他透過不滅者核心，使用著從米娜小姐身上提取出來的逆卡巴拉因子。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"이런, 놀라운데?","JPN":"これは驚いたな。","ENG":"I'm quite impressed!","TWN":"喔，真是讓人驚訝呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"겨우 그 짧은 몇 번의 공방을 통해서 거기까지 눈치채다니......","JPN":"あの短い攻防だけで、そこまで把握するとは……","ENG":"You've noticed so many things in so little time.","TWN":"從這麼短短的幾次攻防中，竟然能察覺到這個地步……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"그 말대로 불멸체 코어는 내 몸에 박혀 있다.","JPN":"君の言うとおり、不滅体コアは私の体に埋め込まれている。","ENG":"Like you said, the Immortal System Core is implanted within my body.","TWN":"就像他說的一樣，不滅者核心就埋在我的身體裡。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"KING_REPLACER_NULL_NULL","text":{"KOREA":"불멸체 코어를 파괴하고 싶다면, 날 먼저 쓰러트려야 하지.","JPN":"不滅体コアを破壊したいなら、私を先に倒さなければならない。","ENG":"If you want to destroy the Core, you'll have to defeat me first.","TWN":"想要破壞不滅者核心，就得先打敗我才行。"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런......","JPN":"そんな……","ENG":"That’s insane...","TWN":"可惡……"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BISHOP_REPLACER_REGEN_NULL","text":{"KOREA":"<color=#ffd34c>최종 재배포 버전 조합 완료율...... 97%</color>","JPN":"<color=#ffd34c>最終再配布版の組み合わせ完了率……97％。</color>","ENG":"<color=#ffd34c>The completion rate of the final redistributable version... 97%.</color>","TWN":"<color=#ffd34c>最終再分發版本組合達成率……97%</color>"},"stage":{"bg":"PROLOGUE_03","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 미나 양은 상냥한 사람이에요.","JPN":"ミナさん、あなたは優しい人です。","ENG":"Mina, have I told you that you're a sweet person?","TWN":"米娜小姐……米娜小姐真是個善良的人呢。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐? 이 상황에 뜬금없이 무슨 소리야?","JPN":"え？　こんな状況で、いきなり何を言いだすの？","ENG":"Huh? H-hey, I don't think this is the right time for small talk.","TWN":"什麼？在這種情況你突然說些什麼啊？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말 그대로입니다.","JPN":"言葉どおりです。","ENG":"I mean it.","TWN":"就是字面上的意思。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"언니를 잃고, 친구를 잃고 PTSD를 겪으면서 세상 모두에게 가시를 세운 채 살아가려고 하고 있지만......","JPN":"お姉さんを失い、友達を失い、数々の傷を抱えたまま、世界に抗い生きていこうとしていますが……","ENG":"You've been suffering from PTSD after losing your sister and your friend, and you've been trying hard to feel hostile against everyone in the world ever since.","TWN":"失去了姐姐，失去了朋友，經歷了創傷後壓力症候群，對世上一切都帶著刺……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양은 원래 상냥한 사람이었겠죠. 적이었던 신나래 양도 그렇게 말했으니까요.","JPN":"ミナさんは元々優しい人だったんでしょうね。敵だったナルミさんも、そう証言していましたし。","ENG":"But you're a sweet person in nature. Even your enemy Shin Narae said so.","TWN":"但米娜小姐本來肯定是個善良的人吧。曾經是敵人的申娜拉也是這麼說的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말로는 비숍을 나래 양과 겹쳐보지 않는다고, 적이라고, 괴물이라고 하지만......","JPN":"表向きには、ビショップとナルミさんは別人だと、\\n彼女は敵であり化け物でしかないと言っていますが……","ENG":"You keep saying that you're not confusing Bishop with Narae, that she's a monster and your enemy,","TWN":"嘴巴上說不會把大主教和娜拉小姐搞混，說她是敵人，是怪物……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그게 진심이 아니라는 걸, 그때마다 미나 양이 스스로를 상처 입히고 있다는 걸 잘 알고 있습니다.","JPN":"それが本心ではないことや、そう発言するたびにミナさんが\\n自らを傷つけているということを、よく知っています。","ENG":"but I know that you don't mean it. I know that you're hurting yourself every time you say it.","TWN":"但我卻知道那不是米娜小姐的真心，也知道妳每次都會受傷。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"저도 마찬가지거든요.","JPN":"僕も同じですからね。","ENG":"I know because I'm exactly like you.","TWN":"我也一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배?","JPN":"先輩？","ENG":"Shiyoon?","TWN":"前輩？"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말했었죠? 제 부모님은 살해당했다고.","JPN":"以前、話しましたよね？　僕の両親は殺されたって。","ENG":"I told you, my parents were murdered.","TWN":"我說過吧？我的父母是被殺害的。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 부모님을 살해한 건 바로 스승님입니다.","JPN":"両親を殺害したのは、師匠なんです。","ENG":"It was Master who killed them.","TWN":"而殺害我的父母的，正是師父。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐?!","JPN":"えっ！？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님은 원래 클리포트 인자 보유자들을 사냥하던 사람입니다.","JPN":"師匠は元々クリフォト・ファクター保持者を狩っていました。","ENG":"Master used to hunt down Qliphoth Factor carriers.","TWN":"師父原來是狩獵逆卡巴拉因子持有者的人。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"기간은 편차가 있지만 가끔 클리포트 인자에 대한 소식을 입수하면 휴가를 내고 사라져서......","JPN":"不定期ではありましたが、たまにクリフォト・ファクター関連の情報が\\n入ったら休暇をとり、姿を消しては……","ENG":"Every once in a while, she would hear the news of a Qliphoth Factor carrier and take a leave of absence...","TWN":"雖然時間不定，但偶爾，只要有逆卡巴拉因子的消息，師父就會請假消失……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>처분</color>하고 돌아오죠.","JPN":"<color=#ffd34c>処分</color>した後、帰ってきていました。","ENG":"to go <color=#ffd34c>dispose of</color> them.","TWN":"<color=#ffd34c>處分</color>後再回來。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제 경우도 마찬가지였습니다.","JPN":"僕の場合も同じです。","ENG":"That was how I met her.","TWN":"我也一樣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용혈의 광기에 잠식된 부모님이 저와 주변의 모든 걸 파괴하려고 했을 때, 그 분들을 참살하고 절 구해 주셨죠.","JPN":"龍血の狂気に侵された両親が、僕やまわりのすべてを破壊しようとした時、\\n彼らを殺して僕のことを救い出してくれました。","ENG":"When my parents succumbed to the madness of the Dragon Blood and were about to destroy everything around them, including myself, she killed them and saved me.","TWN":"當我的父母被龍血的狂氣侵蝕，準備要破壞我和四周一切的時候，師父殺了他們把我救了出來。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 어째서인지 용혈을 물려받은 전 죽이지 않고 그대로 놔두더군요.","JPN":"僕は龍血を受け継いでいたのに、なぜか殺さずに見逃したんです。","ENG":"But for some reason, she chose to spare my life, even though she knew that I had Dragon Blood running in my veins.","TWN":"但不知道為什麼，師父沒有殺掉遺傳龍血的我。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"단순히 용혈...... 클리포트 인자를 아직 사용하지 않았기 때문인지, 다른 이유가 있는 건지는 모릅니다만......","JPN":"それは単に龍血……クリフォト・ファクターをまだ使っていなかったからか、\\nもしくは別の理由があったからかは釈然としませんが……","ENG":"I don't know if it was because I never used the Dragon Blood—the Qliphoth Factor—or if there was some other reason.","TWN":"不知道是不是……我還沒有使用龍血……逆卡巴拉因子，還是有什麼別的原因……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그 날 이후로 스승님을 어떻게 대해야 할지 모르게 되었습니다.","JPN":"僕はその日以降、師匠とどう接すれば良いかわからなくなりました。","ENG":"But after that day, I was torn between the feelings I had for Master.","TWN":"但從那天之後，我就不知道該怎麼面對師父。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"부모님을 살해한 원수인지...... 부모에게 살해당할 뻔한 아이를 구해 준 은인인지......","JPN":"親を殺した仇なのか……それとも、親に殺されかけたところを救ってくれた恩人なのか……","ENG":"I wasn't sure if she was a murderer of my family, or a savior of a child who was almost killed by his own parents.","TWN":"她是殺害了我父母的敵人……還是把差點被父母殺害的孩子救出來的恩人……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그래서 전...... 결정을 미뤄두기로 했죠.","JPN":"それで僕は……自分の判断を保留にしたんです。","ENG":"So... I decided to hold off making a decision.","TWN":"所以我……決定先不要下決定。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님을 용서하거나 증오하기 전에 스승님이 어째서 클리포트 인자 보유자들을 사냥하고 다니는지,","JPN":"師匠を許したり憎んだりする前に、師匠がなぜクリフォト・ファクター保持者を追いかけていたのか、","ENG":"Before I decided how I should feel about Master, I wanted to know why she has been hunting down Qliphoth Factor carriers,","TWN":"在原諒，或是憎恨師父之前，師父為什麼要狩獵逆卡巴拉因子的持有者……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"용혈이란 무엇이고 제 부모님은 왜 죽어야 했는지...... 그 이유를 알아내기로 했습니다.","JPN":"龍血とはどんなもので、僕の両親はなぜ死ななければならなかったのか……\\nそのわけを探ろうと決めました。","ENG":"what the Dragon Blood truly was, and why my parents had to die.","TWN":"龍血到底是什麼，我的父母又為什麼非死不可……我決定去尋找這一切的原因。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 내게......","JPN":"だから、私に……","ENG":"So that's why you were interested in me.","TWN":"所以我……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"네, 제가 알기로 스승님이 클리포트 인자 사용자를 그냥 놔둔 건 미나 양뿐입니다.","JPN":"はい、僕の知っている限り、クリフォト・ファクター保持者であることを知りながら、\\n師匠が手を付けないのは、ミナさんたった一人だけです。","ENG":"Yes. As far as I know, you're the only Qliphoth Factor carrier that Master didn't do anything to.","TWN":"沒錯。就我所知，師父放過的逆卡巴拉因子持有者，只有米娜小姐而已。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니 제가 미나 양에게 관심을 가질 법도 하죠.","JPN":"だからこそ、僕はミナさんに興味津々なんです。","ENG":"No wonder I was interested in knowing you.","TWN":"所以我對米娜小姐很感興趣。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서와 관련된 일도 마찬가지입니다. KS-1에서 리플레이서 나이트와 조우했을 때 스승님은 분명 무언가를 아는 눈치였어요.","JPN":"リプレイサーに関わる件も同じです。\\nKS-1でリプレイサー・ナイトと遭遇した時、師匠は間違いなく何かを知っている印象でした。","ENG":"It was the same about this Replacer subjugation. When we ran into the Replacer Knight at KS-1, I could tell Master caught on to something.","TWN":"和克隆集團有關的事情也一樣。在KS-1遇到克隆·騎士的時候，師父很明顯知道些什麼。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제가 어울리지 않게 이 일에 적극적으로 나선 건 이번 일이 스승님의 과거를 추적할 수 있는 실마리가 될 거란 생각에서였습니다.","JPN":"僕が柄にもなく今回の件に積極的なのは、\\nこれが師匠の過去を知るための糸口になりそうだったからです。","ENG":"The reason why I decided to get myself involved in a mission like this, which is something I almost never do, was that I thought I'd find a clue to Master's past.","TWN":"我之所以會這麼不像我，表現得這麼積極，就是因為覺得這次的事件是能夠追溯到師父過去的線索。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"결과적으로 어느 정도의 소득도 있었고요.","JPN":"結果として、ある程度得るものもありましたし。","ENG":"And I was right, in that I've come to learn some meaningful things.","TWN":"從結果上來看，我是有一點發現。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 복수를 미룬 그 시점에서, 어쩌면 전 제 자신을 속이고 있었던 걸지도 몰라요.","JPN":"でも……復讐を先延ばしにした時点で、僕はひょっとしたら自らを欺いていたのかもしれません。","ENG":"However... I can't be free from the thought that I've been deceiving myself the whole time, ever since I decided to delay my revenge.","TWN":"但是……在決定延後報仇的那個時點開始，我大概就是在自欺欺人吧。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"최근에 만난 누군가가 그렇게 말하더군요.","JPN":"最近会った誰かがこう言っていました。","ENG":"Someone I met recently told me","TWN":"最近我遇見的某個人是這麼說的。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 그저 스승님을 용서할 이유를 찾고 있던 것일 뿐이라고.","JPN":"あなたは単に、師匠を許す口実を探していただけって。","ENG":"that I was just looking for a reason to forgive Master.","TWN":"說我只是在找一個原諒師父的理由。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양에게는 잘난 척하곤 했지만 따지고 보면 저도 아직 PTSD를 극복하지 못한 거겠죠","JPN":"ミナさんには強がっていましたが、僕もまだ当時の傷を克服できていないんでしょうね。","ENG":"I talked big in front of you, but I guess I'm still suffering from PTSD.","TWN":"雖然我一直在米娜小姐面前耍帥，但仔細想想，我也還沒克服創傷後壓力症候群吧。"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"MAINSTREAM_430010","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양, 사람은 누구나 타인에게 이해 받지 못하는 부분이 있습니다.","JPN":"ミナさん、あらゆる人間には他人に理解してもらえないところがあります。","ENG":"Everyone has a side that others don't really understand, Mina.","TWN":"米娜小姐，不管是誰，都有別人無法理解的部分。"},"stage":{"bg":"MAINSTREAM_345014","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"심지어는 스스로도 이해하지 못할 정도로 불합리하지만......","JPN":"酷い場合は、自ら理解できないほどに、筋が通っていないけど……","ENG":"It's one of the things that you know is unreasonable, but you still need to hold onto.","TWN":"甚至，是連自己都無法理解自己的那樣沒道理……"},"stage":{"bg":"MAINSTREAM_345014","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"반드시 그렇게 선택하고야 마는, 양보했다간 자기 자신이 아니게 되어 버리는 부분 말입니다.","JPN":"そうせざるを得ない、そこを譲ってしまうと自分が自分じゃなくなるような、そんなところです。","ENG":"Something that you need to have in you to keep existing as who you are.","TWN":"但妳非得那樣選擇不可，一旦退讓，妳就會失去自我的那部分。"},"stage":{"bg":"MAINSTREAM_345014","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"제게는 유예할 시간이 있었지만...... 미나 양에겐 여유가 없군요.","JPN":"僕には保留にできる時間がありましたが……ミナさんにはそんな余裕がありませんね。","ENG":"I had the time to suspend my decision, but I'm afraid that's not the case for you.","TWN":"我雖然有猶豫的時間……但是米娜小姐卻沒有喔。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어떤 결정을 하든, 그건 미나 양의 몫입니다.","JPN":"どんな決定をしようとも、それはミナさん次第です。","ENG":"The choice is yours, whatever it may be.","TWN":"要做出什麼樣的決定，都取決於米娜小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 결정을 하지 않고 그저 흘려버리지는 마세요.","JPN":"ただ、決めずに流してしまおうなんてことはしないでください。","ENG":"But don't let this moment go by without making a decision.","TWN":"但就是不要不做決定，讓事情這麼過去。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그랬다가는...... 미나 양은 더 이상 미나 양이 아니게 될 테니까요.","JPN":"それじゃ……ミナさんはそれ以上ミナさんではなくなりますから。","ENG":"If you do, you won't be able to stay as who you are anymore.","TWN":"那樣的話……米娜小姐就不是米娜小姐了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스승님이 특별하게 생각하는 유일한 사람이 그런 꼴이 되는 건...... 별로 보고 싶지 않거든요.","JPN":"師匠が特別視する唯一の人が、そんな風になるのは……あまり見たくないですからね。","ENG":"You're the only person who Master thinks special, and I'd hate to see you lose yourself.","TWN":"我不想看到……師父唯一特殊對待的人變成那個樣子。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배......","JPN":"先輩……","ENG":"Shiyoon...","TWN":"前輩……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그럼 전 시간을 벌러 가보겠습니다.","JPN":"それじゃ、僕は時間稼ぎに行ってみます。","ENG":"Then I'll go stall for time.","TWN":"那麼我去爭取時間了。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"스스로에게 솔직할 기회를...... 놓치지 마세요, 미나 양.","JPN":"自分の気持ちに正直になるチャンスを……逃さないでくださいね、ミナさん。","ENG":"Don't miss this chance to be honest with yourself, Mina.","TWN":"不要錯過……能真誠面對自己的機會，米娜小姐。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BOOM"}]`);export{e as default};